import React, { useEffect, useState } from 'react';
import Navbar from '../../components/Navbar';
import api from '../../api/axiosInstance';
import styles from './AdminPages.module.css';

const ManagePackagesPage = () => {

  const [packages, setPackages] = useState([]);
  const [loading, setLoading]   = useState(true);
  const [error, setError]       = useState('');

  // form state
  const [formData, setFormData] = useState({
    name: '',
    description: '',
    destination: '',
    duration: '',
    price: '',
    availableSlots: ''
  });

  // load packages
  const load = () => {
    setLoading(true);
    api.get('/packages')
      .then((res) => setPackages(res.data?.data || []))
      .catch(() => setError('Failed to load packages.'))
      .finally(() => setLoading(false));
  };

  useEffect(load, []);

  // delete package
  const deletePackage = async (id) => {
    if (!window.confirm('Delete this package?')) return;
    try {
      await api.delete(`/packages/${id}`);
      load();
    } catch {
      alert('Delete failed.');
    }
  };

  // handle form input change
  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  // add new package
  const addPackage = async (e) => {
    e.preventDefault();

    try {
      await api.post('/packages', formData);

      alert('Package added successfully');

      // reset form
      setFormData({
        name: '',
        description: '',
        destination: '',
        duration: '',
        price: '',
        availableSlots: ''
      });

      load();

    } catch {
      alert('Failed to add package');
    }
  };

  return (
    <>
      <Navbar />

      <div className={styles.page}>

        <h1>✈️ Manage Packages</h1>

        {/* ADD PACKAGE FORM */}

        <form onSubmit={addPackage} style={{marginBottom:'30px'}}>

          <h3>Add New Package</h3>

          <input
            type="text"
            name="name"
            placeholder="Package Name"
            value={formData.name}
            onChange={handleChange}
            required
          />

          <input
            type="text"
            name="destination"
            placeholder="Destination ID"
            value={formData.destination}
            onChange={handleChange}
            required
          />

          <input
            type="number"
            name="duration"
            placeholder="Duration (days)"
            value={formData.duration}
            onChange={handleChange}
            required
          />

          <input
            type="number"
            name="price"
            placeholder="Price"
            value={formData.price}
            onChange={handleChange}
            required
          />

          <input
            type="number"
            name="availableSlots"
            placeholder="Available Slots"
            value={formData.availableSlots}
            onChange={handleChange}
            required
          />

          <textarea
            name="description"
            placeholder="Description"
            value={formData.description}
            onChange={handleChange}
          />

          <button type="submit">Add Package</button>

        </form>

        {/* PACKAGE TABLE */}

        {loading && <p>Loading…</p>}
        {error && <p style={{ color: 'red' }}>{error}</p>}

        {!loading && !error && (

          <table className={styles.table}>

            <thead>
              <tr>
                <th>Name</th>
                <th>Destination</th>
                <th>Duration</th>
                <th>Price</th>
                <th>Actions</th>
              </tr>
            </thead>

            <tbody>

              {packages.length === 0 ? (
                <tr>
                  <td colSpan={5}>No packages found.</td>
                </tr>
              ) : packages.map((p) => (

                <tr key={p._id}>

                  <td>{p.name}</td>

                  <td>{p.destination?.name || '—'}</td>

                  <td>{p.duration} days</td>

                  <td>${p.price}</td>

                  <td className={styles.actions}>

                    <button
                      className={`${styles.btnSm} ${styles.btnDanger}`}
                      onClick={() => deletePackage(p._id)}
                    >
                      Delete
                    </button>

                  </td>

                </tr>

              ))}

            </tbody>

          </table>

        )}

      </div>
    </>
  );
};

export default ManagePackagesPage;
